import React, { useState, useEffect } from 'react';
import { MapPin, ShoppingBag, ShoppingCart } from 'lucide-react';
import { validateCartAddition } from '../utils/cartHelpers';
import Carrito from './Carrito';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [cart, setCart] = useState([]);

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];
    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      acumulador = [...acumulador, ...ofertasLocal.map(o => ({
        ...o,
        localId: local.id,
        nombreLocal: local.nombre,
        direccionLocal: local.direccion,
        ciudad: local.ciudad
      }))];
    });
    setTodasLasOfertas(acumulador);
  }, []);

  const agregarAlCarrito = (producto) => {
    // Validamos siempre contra delivery por defecto por seguridad
    const check = validateCartAddition(cart, producto, 'delivery');
    if (!check.valid) return alert(check.msg);

    setCart([...cart, producto]);
  };

  const finalizarCompra = () => {
    alert("¡Compra realizada con éxito! Recibirás un correo con los detalles.");
    setCart([]);
  };

  return (
    <div style={{ display: 'flex', gap: '30px', padding: '40px 5%', background: '#f8fafc', minHeight: '100vh' }}>
      
      {/* GRILLA DE PRODUCTOS */}
      <div style={{ flex: 1 }}>
        <h2 style={{ marginBottom: '25px' }}>Ofertas Disponibles</h2>
        <div style={grid}>
          {todasLasOfertas.map(o => (
            <div key={o.id} style={card}>
              <div style={cardBody}>
                <span style={label}>{o.nombreLocal}</span>
                <h3 style={{ margin: '5px 0' }}>{o.producto}</h3>
                <p style={pesoTag}>{o.peso} kg</p>
                <div style={priceRow}>
                  <span style={price}>${o.precioNuevo}</span>
                  <button onClick={() => agregarAlCarrito(o)} style={btnAdd}>
                    <ShoppingCart size={18} />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* CARRITO LATERAL (Solo aparece si hay items) */}
      {cart.length > 0 && (
        <Carrito 
          cart={cart} 
          setCart={setCart} 
          onCheckout={finalizarCompra} 
        />
      )}
    </div>
  );
};

const grid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: '20px' };
const card = { background: 'white', borderRadius: '15px', border: '1px solid #e2e8f0', overflow: 'hidden' };
const cardBody = { padding: '15px' };
const label = { fontSize: '0.7rem', fontWeight: 'bold', color: '#e67e22', textTransform: 'uppercase' };
const pesoTag = { fontSize: '0.8rem', color: '#94a3b8', marginBottom: '10px' };
const priceRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const price = { fontSize: '1.4rem', fontWeight: 'bold', color: '#1e293b' };
const btnAdd = { background: '#1e293b', color: 'white', border: 'none', padding: '10px', borderRadius: '10px', cursor: 'pointer' };

export default PanelCliente;
